"use strict";

/* LEAD() — एक बड़े-नाम की पूरी <li> बनाने वाला साझा-टुकड़ा (भविष्य के सब उद्यमों में यही दोहराया जाए)।
   nameHi = देवनागरी नाम (Roman कोष्ठक समेत) · url = आधिकारिक वेबसाइट (जाँची हुई)
   mapQuery = "कंपनी-नाम, शहर, देश" (सादा टेक्स्ट — encodeURIComponent ख़ुद करता है)
   desc = एक-पंक्ति परिचय */
function LEAD(nameHi, url, mapQuery, desc){
  const mapUrl = "https://www.google.com/maps/search/?api=1&query=" + encodeURIComponent(mapQuery);
  return "<li><a href=\"" + url + "\" target=\"_blank\" rel=\"noopener\">" + nameHi + "</a> " +
    "<a class=\"udy-maplink\" href=\"" + mapUrl + "\" target=\"_blank\" rel=\"noopener\">📍 नक़्शा</a> — " + desc + "</li>";
}

